from typing import Dict, List, Optional, Any
from dataclasses import dataclass
from enum import Enum
import uuid
from datetime import datetime

class UserTier(Enum):
    REGULAR = "regular"
    PREMIUM = "premium"
    VIP = "vip"

class DiscountCodeType(Enum):
    PUBLIC = "public"
    PREMIUM = "premium"
    VIP = "vip"
    ADMIN = "admin"

@dataclass
class CartItem:
    product_id: str
    quantity: int
    price: float

@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountCodeType
    discount_value: float
    valid_for_tiers: List[UserTier]
    is_active: bool

@dataclass
class Order:
    order_id: str
